Below is a Java program that uses **JavaFX** for image processing and saving:

### Java Program

```java
import java.awt.image.BufferedImage;
import java.io.*;
import java.net.URL;
import java.nio.file.Files;
import java.nio.file.Paths;
import javax.imageio.ImageIO;
import javafx.application.Application;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;
import javafx.scene.image.PixelFormat;
import javafx.scene.image.WritableImage;
import javafx.scene.layout.StackPane;
import javafx.stage.Stage;

public class ImageFilterApp extends Application {

    public static void main(String[] args) {
        launch(args);
    }

    @Override
    public void start(Stage primaryStage) {
        // URL of the image to download
        String imageUrl = "https://example.com/path/to/image.jpg";

        // Download the image
        BufferedImage originalImage = downloadImage(imageUrl);

        // Apply a grayscale filter
        BufferedImage grayscaleImage = applyGrayscaleFilter(originalImage);

        // Save the processed image
        saveImage(grayscaleImage, "processed_image.jpg");

        // Display the image
        displayImage(grayscaleImage);
    }

    private BufferedImage downloadImage(String imageUrl) {
        try {
            URL url = new URL(imageUrl);
            BufferedImage image = ImageIO.read(url.openStream());
            return image;
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

    private BufferedImage applyGrayscaleFilter(BufferedImage image) {
        int width = image.getWidth();
        int height = image.getHeight();
        BufferedImage result = new BufferedImage(width, height, BufferedImage.TYPE_INT_RGB);

        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                int pixel = image.getRGB(x, y);
                int r = (pixel >> 16) & 0xFF;
                int g = (pixel >> 8) & 0xFF;
                int b = pixel & 0xFF;

                int gray = (r + g + b) / 3;
                result.setRGB(x, y, (gray << 16) | (gray << 8) | gray);
            }
        }

        return result;
    }

    private void saveImage(BufferedImage image, String filename) {
        try (FileOutputStream fos = new FileOutputStream(filename)) {
            ImageIO.write(image, "jpg", fos);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private void displayImage(BufferedImage image) {
        try {
            ImageIO.write(image, "jpg", new File("display_image.jpg"));
            ImageView imageView = new ImageView(new Image(Files.newInputStream(Paths.get("display_image.jpg"))));
            StackPane root = new StackPane();
            root.getChildren().add(imageView);
            primaryStage.setScene(new Scene(root, 800, 600));
            primaryStage.show();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
```

### Explanation

- **`downloadImage`**: Downloads the image from the given URL.
- **`applyGrayscaleFilter`**: Converts the image to grayscale using a simple average of the RGB values.
- **`saveImage`**: Saves the processed image to a file.
- **`displayImage`**: Displays the processed image in a JavaFX window.

