## Script: `haversine.pl`

```perl
use strict;
use warnings;
use Getopt::Long;
use JSON;

# Define constants
my $KILOMETERS = 1;
my $MILES = 1;

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371; # Earth radius in kilometers

    # Convert degrees to radians
    my $lat1_rad = radians($lat1);
    my $lon1_rad = radians($lon1);
    my $lat2_rad = radians($lat2);
    my $lon2_rad = radians($lon2);

    # Haversine formula
    my $a = sin($lat1_rad - $lat2_rad) ** 2 +
           cos($lat1_rad) * cos($lat2_rad) * sin($lat1_rad - $lat2_rad) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Convert degrees to radians
sub radians {
    return deg2rad($_[0]);
}

# Convert radians to degrees
sub deg2rad {
    return $_[0] * pi() / 180;
}

# Main script
sub main {
    my $help = 0;
    my $km = 1;
    my $mi = 1;

    # Parse command-line arguments
    GetOptions(
        "help" => \$help,
        "km" => \$km,
        "mi" => \$mi,
    ) or die "Usage: $0 [options]\n";

    # Check if help is requested
    if ($help) {
        print "Usage: $0 [options]\n";
        print "Options:\n";
        print "  -h,--help            Show this help message\n";
        print "  -k,--km             Output distance in kilometers\n";
        print "  -m,--mi             Output distance in miles\n";
        print "  -l,--lat1,--lat2    Specify the latitude and longitude of the two locations\n";
        print "  -n,--name1,--name2  Specify the names of the two locations\n";
        print "\n";
        exit;
    }

    # Check if both locations are provided
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Error: Both latitude and longitude are required.\n";
    }

    # Validate input
    if (!is_valid_lat_lon($lat1) || !is_valid_lat_lon($lon1) || !is_valid_lat_lon($lat2) || !is_valid_lat_lon($lon2)) {
        die "Error: Invalid latitude or longitude values.\n";
    }

    # Calculate distance
    my $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);
    my $unit = $km ? "km" : $mi ? "mi" : "km";

    # Output results
    print "Distance between $name1 and $name2 is $distance $unit.\n";
}

