use strict;
use warnings;

# Function to merge two sorted arrays in descending order
sub merge {
    my ($left, $right) = @_;
    my @merged;

    # Merge the two arrays while maintaining descending order
    while (scalar @$left > 0 && scalar @$right > 0) {
        if ($left->[0] >= $right->[0]) {
            $merged.unshift($left->[0]);
            shift @$left;
        } else {
            $merged.unshift($right->[0]);
            shift @$right;
        }
    }

    # Append remaining elements from left or right
    while (scalar @$left > 0) {
        $merged.unshift($left->[0]);
        shift @$left;
    }

    while (scalar @$right > 0) {
        $merged.unshift($right->[0]);
        shift @$right;
    }

    return \@merged;
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($arr) = @_;
    return $arr if @$arr <= 1;

    my $mid = @$arr / 2;
    my $left = merge_sort(first($arr, $mid));
    my $right = merge_sort(last($arr, $mid));

    return merge($left, $right);
}

